package com.treeeducation.ioas.audit; import jakarta.persistence.*;import java.time.Instant; /** Immutable operation audit log. */ @Entity @Table(name="audit_log") public class AuditLog{ @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Enumerated(EnumType.STRING) @Column(nullable=false,length=40) private AuditAction action; @Column(nullable=false,length=40) private String targetType; @Column(nullable=false) private Long targetId; @Column(nullable=false) private Long actorId; @Column(length=2000) private String detail; @Column(nullable=false) private Instant createdAt=Instant.now(); public Long getId(){return id;} public void setId(Long id){this.id=id;} public AuditAction getAction(){return action;} public void setAction(AuditAction action){this.action=action;} public String getTargetType(){return targetType;} public void setTargetType(String targetType){this.targetType=targetType;} public Long getTargetId(){return targetId;} public void setTargetId(Long targetId){this.targetId=targetId;} public Long getActorId(){return actorId;} public void setActorId(Long actorId){this.actorId=actorId;} public String getDetail(){return detail;} public void setDetail(String detail){this.detail=detail;} public Instant getCreatedAt(){return createdAt;} public void setCreatedAt(Instant createdAt){this.createdAt=createdAt;} }
